('Sundance Film Festival 2027', 'Liên hoan phim Sundance 2027', 'USA', 'Park City', 'https://sundance.org', 'documentary', 'A-list', '2026-08-15', '2026-09-15', 'One of the most prestigious independent film festivals in the world.', 'Một trong những liên hoan phim độc lập uy tín nhất thế giới.', 'manual'),
('IDFA Amsterdam 2026', 'IDFA Amsterdam 2026', 'Netherlands', 'Amsterdam', 'https://idfa.nl', 'documentary', 'A-list', '2026-06-01', '2026-07-15', 'International Documentary Film Festival Amsterdam.', 'Liên hoan phim tài liệu quốc tế Amsterdam.', 'manual'),
('Busan International Film Festival 2026', 'Liên hoan phim quốc tế Busan 2026', 'South Korea', 'Busan', 'https://biff.kr', 'narrative', 'A-list', '2026-05-01', '2026-06-30', 'Asia''s leading film festival.', 'Liên hoan phim hàng đầu châu Á.', 'manual'),
('Hot Docs 2026', 'Hot Docs 2026', 'Canada', 'Toronto', 'https://hotdocs.ca', 'documentary', 'A-list', '2026-10-01', '2026-11-15', 'North America''s largest documentary festival.', 'Liên hoan phim tài liệu lớn nhất Bắc Mỹ.', 'manual');
INSERT INTO funds_grants (name, name_vi, organization, country, website, type, focus, region_focus, max_amount, currency, deadline, eligibility, eligibility_vi, description, description_vi) VALUES
('Hubert Bals Fund', 'Quỹ Hubert Bals', 'International Film Festival Rotterdam (IFFR)', 'Netherlands', 'https://iffr.com/en/professionals/hubert-bals-fund', 'development', 'narrative', 'global', 10000, 'EUR', '2026-09-01', 'Filmmakers from Asia, Africa, Latin America, Middle East, and Eastern Europe.', 'Nhà làm phim từ châu Á, châu Phi, Mỹ Latinh, Trung Đông và Đông Âu.', 'Supports script and project development for feature films and creative documentaries from developing countries.', 'Hỗ trợ phát triển kịch bản và dự án phim dài và phim tài liệu sáng tạo từ các nước đang phát triển.'),
('IDFA Bertha Fund', 'Quỹ IDFA Bertha', 'International Documentary Film Festival Amsterdam (IDFA)', 'Netherlands', 'https://www.idfa.nl/en/info/idfa-bertha-fund', 'production', 'documentary', 'global', 40000, 'EUR', '2026-05-01', 'Documentary filmmakers from developing countries.', 'Nhà làm phim tài liệu từ các nước đang phát triển.', 'Supports documentary filmmakers from Africa, Asia, Latin America, Middle East and parts of Europe.', 'Hỗ trợ nhà làm phim tài liệu từ châu Phi, châu Á, Mỹ Latinh, Trung Đông và một số nước châu Âu.'),
('Sundance Documentary Fund', 'Quỹ phim tài liệu Sundance', 'Sundance Institute', 'USA', 'https://www.sundance.org/programs/documentary-fund', 'production', 'documentary', 'global', 30000, 'USD', '2026-06-15', 'Documentary filmmakers with a focus on social justice issues.', 'Nhà làm phim tài liệu tập trung vào các vấn đề công bằng xã hội.', 'Supports global documentary projects that address pressing social, cultural, and political issues.', 'Hỗ trợ các dự án phim tài liệu quốc tế đề cập đến các vấn đề xã hội, văn hóa và chính trị cấp bách.'),
('World Cinema Fund', 'Quỹ Điện ảnh Thế giới', 'Berlinale — Berlin International Film Festival', 'Germany', 'https://www.berlinale.de/en/world-cinema-fund/overview.html', 'development', 'narrative', 'global', 60000, 'EUR', '2026-10-15', 'Feature films from Africa, Latin America, Central/Southeast Asia, Middle East, and Eastern Europe.', 'Phim dài từ châu Phi, Mỹ Latinh, Trung/Đông Nam Á, Trung Đông và Đông Âu.', 'Supports the production and distribution of art-house feature films from underrepresented regions.', 'Hỗ trợ sản xuất và phát hành phim dài nghệ thuật từ các khu vực ít được đại diện.'),
('Asian Cinema Fund', 'Quỹ Điện ảnh châu Á', 'Busan International Film Festival (BIFF)', 'South Korea', 'https://acf.busan.go.kr', 'development', 'narrative', 'asia', 20000, 'USD', '2026-04-30', 'Filmmakers from Asian countries.', 'Nhà làm phim từ các quốc gia châu Á.', 'Script development and post-production support for Asian cinema projects.', 'Hỗ trợ phát triển kịch bản và hậu kỳ cho các dự án điện ảnh châu Á.'),
('SEAFIC Lab', 'SEAFIC Lab', 'Southeast Asian Fiction Film Lab', 'Thailand', 'https://www.seafic.net', 'development', 'narrative', 'southeast-asia', 15000, 'USD', '2026-07-31', 'Filmmakers from ASEAN countries for narrative feature development.', 'Nhà làm phim từ các nước ASEAN phát triển phim truyện dài.', 'Script and project development for Southeast Asian fiction films. Annual lab with mentorship and funding.', 'Phát triển kịch bản và dự án phim truyện Đông Nam Á. Lab hàng năm với cố vấn và tài trợ.'),
('Catapult Film Fund', 'Quỹ Catapult Film', 'Catapult Film Fund', 'USA', 'https://catapultfilmfund.org', 'development', 'documentary', 'global', 25000, 'USD', '2026-08-15', 'Documentary filmmakers in development phase.', 'Nhà làm phim tài liệu trong giai đoạn phát triển.', 'Development funding for documentary films. Provides early-stage funding to help documentarians develop their films.', 'Tài trợ phát triển cho phim tài liệu. Cung cấp kinh phí giai đoạn đầu giúp nhà làm phim phát triển tác phẩm.'),
('Doha Film Institute Development Grant', 'Tài trợ Phát triển Viện phim Doha', 'Doha Film Institute', 'Qatar', 'https://www.dohafilminstitute.com/filmmaking/grants', 'development', 'narrative', 'global', 30000, 'USD', '2026-05-31', 'Arab filmmakers and global co-productions.', 'Nhà làm phim Ả Rập và đồng sản xuất quốc tế.', 'Script development and production funding for Arab and international filmmakers.', 'Tài trợ phát triển kịch bản và sản xuất cho nhà làm phim Ả Rập và quốc tế.'),
('Hot Docs Forum', 'Hot Docs Forum', 'Hot Docs Canadian International Documentary Festival', 'Canada', 'https://hotdocs.ca/programmes/hot-docs-forum', 'production', 'documentary', 'global', NULL, 'USD', '2026-11-15', 'Documentary projects seeking co-production and financing partners.', 'Các dự án phim tài liệu tìm kiếm đối tác đồng sản xuất và tài chính.', 'Pitching forum connecting documentary filmmakers with international broadcasters and distributors.', 'Diễn đàn pitch kết nối nhà làm phim tài liệu với các đài truyền hình và nhà phân phối quốc tế.'),
('Purin Pictures Fund', 'Quỹ Purin Pictures', 'Purin Pictures', 'Thailand', 'https://www.purinpictures.com', 'development', 'narrative', 'southeast-asia', 20000, 'USD', '2026-06-30', 'Southeast Asian narrative filmmakers.', 'Nhà làm phim truyện Đông Nam Á.', 'Development and production support for Southeast Asian cinema with focus on emerging voices.', 'Hỗ trợ phát triển và sản xuất điện ảnh Đông Nam Á tập trung vào các tiếng nói mới nổi.'),
('ITVS Open Call', 'ITVS Open Call', 'Independent Television Service (ITVS)', 'USA', 'https://itvs.org/funding/open-call', 'production', 'documentary', 'global', 200000, 'USD', '2026-09-30', 'Independent documentary filmmakers for PBS broadcast.', 'Nhà làm phim tài liệu độc lập cho đài PBS.', 'Funds independent documentary films for broadcast on PBS, with focus on diverse voices and underrepresented communities.', 'Tài trợ phim tài liệu độc lập phát sóng trên PBS, tập trung vào tiếng nói đa dạng và cộng đồng ít được đại diện.'),
('CNC Aide aux cinémas du monde', 'CNC Aide aux cinémas du monde', 'Centre national du cinéma et de limage animée (CNC)', 'France', 'https://www.cnc.fr/professionnels/aides-et-financements/international/aide-aux-cinemas-du-monde', 'production', 'narrative', 'global', 80000, 'EUR', '2026-09-15', 'French-international co-productions with directors from non-EU countries.', 'Đồng sản xuất Pháp-quốc tế với đạo diễn từ các nước ngoài EU.', 'French co-production fund supporting international films directed by filmmakers from non-EU countries.', 'Quỹ đồng sản xuất Pháp hỗ trợ phim quốc tế do đạo diễn từ các nước ngoài EU thực hiện.'),
('Chicken & Egg Pictures Fund', 'Quỹ Chicken & Egg Pictures', 'Chicken & Egg Pictures', 'USA', 'https://chickeneggpics.org', 'production', 'documentary', 'global', 50000, 'USD', '2026-07-01', 'Women-identifying and non-binary documentary filmmakers.', 'Nhà làm phim tài liệu nhận dạng là phụ nữ và phi nhị phân.', 'Supports women-identifying and non-binary nonfiction filmmakers who are underrepresented and under-resourced.', 'Hỗ trợ nhà làm phim phi hư cấu nhận dạng là phụ nữ và phi nhị phân ít được đại diện và thiếu nguồn lực.'),
('Cinemart Co-Production Market', 'Cinemart Thị trường Đồng sản xuất', 'International Film Festival Rotterdam (IFFR)', 'Netherlands', 'https://iffr.com/en/professionals/cinemart', 'development', 'narrative', 'global', NULL, 'EUR', '2026-08-01', 'Feature film projects seeking co-production and financing.', 'Dự án phim dài tìm kiếm đồng sản xuất và tài chính.', 'International co-production and finance market for independent feature films at IFFR Rotterdam.', 'Thị trường đồng sản xuất và tài chính quốc tế cho phim dài độc lập tại IFFR Rotterdam.'),
('Tribeca Film Institute Documentary Fund', 'Quỹ phim tài liệu Tribeca Film Institute', 'Tribeca Film Institute', 'USA', 'https://www.tribecafilminstitute.org', 'production', 'documentary', 'global', 25000, 'USD', '2026-05-15', 'Documentary filmmakers working on social-issue films.', 'Nhà làm phim tài liệu làm phim về vấn đề xã hội.', 'Supports documentary films that illuminate contemporary social issues and amplify underrepresented voices.', 'Hỗ trợ phim tài liệu phản ánh các vấn đề xã hội đương đại và khuếch đại những tiếng nói ít được đại diện.');
